2. Move client handler span propagation into the new accept_handle's loop
3. Add span propagation to the new accept_handle thread itself

The new accept_handle structure:
```rust
let accept_span = tracing::Span::current();
let accept_handle = std::thread::spawn(move || {
    accept_span.in_scope(|| {
        loop {
            // ... accept logic ...
            let client_span = tracing::Span::current();
            std::thread::spawn(move || {
                client_span.in_scope(|| handle_client(...));
            });
        }
    });
});
```

