**CLI command**:
```rust
#[derive(Parser)]
pub struct ResolveConflictsArgs {
    /// File to resolve (defaults to .beads/issues.jsonl)
    file: Option<PathBuf>,

    #[arg(long, default_value = "mechanical")]
    mode: ResolutionMode,

    #[arg(long)]
    dry_run: bool,

    #[arg(long)]
    json: bool,

    #[arg(long)]
    path: Option<PathBuf>,
}

pub fn resolve_conflicts(args: ResolveConflictsArgs) -> Result<()> {
    let file_path = args.file.unwrap_or_else(|| {
        args.path.unwrap_or_else(|| PathBuf::from("."))
            .join(".beads/issues.jsonl")
    });

    // Read file
    let content = fs::read_to_string(&file_path)?;

    // Parse conflicts
    let (conflicts, clean_lines) = parse_conflicts(&content)?;

    if conflicts.is_empty() {
        println!("No conflict markers found");
        return Ok(());
    }

    // Resolve each conflict
    let resolver = ConflictResolver::new(args.mode);
    let mut resolved_lines = clean_lines;

    for conflict in &conflicts {
        let resolved = resolver.resolve(conflict)?;
        resolved_lines.extend(resolved);
    }

    if args.dry_run {
        println!("Would resolve {} conflicts", conflicts.len());
        return Ok(());
    }

    // Create backup
    let backup_path = file_path.with_extension("jsonl.pre-resolve");
    fs::copy(&file_path, &backup_path)?;

    // Write resolved file atomically
    let temp_path = file_path.with_extension("jsonl.tmp");
    fs::write(&temp_path, resolved_lines.join("\n"))?;
    fs::rename(&temp_path, &file_path)?;

    println!("Resolved {} conflicts", conflicts.len());
    println!("Backup: {}", backup_path.display());

    Ok(())
}
